FROM energy_used eu
WHERE eu.time_type = 'MONTH'
  AND eu.point_id IN (
      SELECT np.point_id FROM node_point np WHERE np.node_id = #{nodeId}
  )
  AND EXTRACT(YEAR  FROM eu.data_time) = #{year}
  AND EXTRACT(MONTH FROM eu.data_time) = #{month}
